import { Calendar } from 'lucide-react';
import { usePathname } from 'next/navigation';
import React from 'react'

interface HeadersProp {
    showDashboardNav?: boolean
}

interface NavigationItem {
    label: string;
    icon: React.ComponentType<any>;
    href: string;
    active: boolean

}

function Headers({ showDashboardNav = false }: HeadersProp) {

    const user = {
        type: "pateint"
    }

    const pathname = usePathname();

    const getDashboardNavigation = (): NavigationItem[] => {
        if (!user || !showDashboardNav) {
            return [];
        }

        if (user?.type === "pateint") {
            return [
                {
                    label: "Appointments",
                    icon: Calendar,
                    href: "/patient/dashboard",
                    active: pathname?.includes("/patient/dashboard") || false
                }
            ]
        } else if (user?.type === "doctor") {
            return [
                {
                    label: "Dashboard",
                    icon: Calendar,
                    href: "/doctor/dashboard",
                    active: pathname?.includes("/doctor/dashboard") || false
                },
                {
                    label: "Appointments",
                    icon: Calendar,
                    href: "/doctor/appointments",
                    active: pathname?.includes("/doctor/appointments") || false
                }
            ]
        }

        return []

    }
    return (
        <div>

        </div>
    )
}

export default Headers;
